function emoMeta(raw) {
  if (!raw) return null;
  const s = String(raw).toLowerCase().trim();
  for (const row of EMO) if (row.k.some(k => s === k)) return row;
  for (const row of EMO) if (row.k.some(k => s.includes(k))) return row;
  return { e: "🎭", c: "#636363" };
}
